package jetbrains.mps.editor.spellcheck;

/*Generated by MPS */

import jetbrains.mps.logging.Logger;
import com.intellij.grazie.jlanguage.Lang;
import com.intellij.grazie.detection.LangDetector;
import org.languagetool.JLanguageTool;
import com.intellij.grazie.jlanguage.LangTool;
import com.intellij.grazie.utils.TextStyleDomain;
import java.util.List;
import org.languagetool.AnalyzedSentence;
import org.languagetool.AnalyzedTokenReadings;
import java.io.IOException;
import org.languagetool.AnalyzedToken;
import jetbrains.mps.baseLanguage.logging.rt.LogContext;

public class NativeLanguageAnalyzer {
  private static final Logger LOG = Logger.getLogger(NativeLanguageAnalyzer.class);
  public static String detectNativeLanguage(String text) {
    if ((text == null || text.length() == 0)) {
      return "Unknown";
    }
    Lang nativeLanguage = LangDetector.INSTANCE.getLang(text);
    return (nativeLanguage == null ? "Unknown" : nativeLanguage.getShortDisplayName());
  }

  public static boolean isActionDescProperlyCapitalized(String text) {
    if ((text == null || text.length() == 0)) {
      return true;
    }
    Lang nativeLanguage = LangDetector.INSTANCE.getLang(text);
    if (nativeLanguage == null) {
      try {
        nativeLanguage = Lang.valueOf("AMERICAN_ENGLISH");
      } catch (IllegalArgumentException e) {
        if (LOG.isWarningLevel()) {
          LOG.warning(String.format("The used native language could not be detected in '%s' and the default AMERICAN_ENGLISH language support cannot be initialized. Capitalization check will be disabled.", text), e);
        }
        return true;
      }
    }
    return isDescProperlyCapitalized(text, nativeLanguage);
  }

  public static boolean isActionDescProperlyCapitalized(String text, String langCode) {
    if ((text == null || text.length() == 0)) {
      return true;
    }
    try {
      Lang nativeLanguage = Lang.valueOf(langCode);
      return isDescProperlyCapitalized(text, nativeLanguage);
    } catch (IllegalArgumentException e) {
      if (LOG.isWarningLevel()) {
        LOG.warning(String.format("The specified %s native language support cannot be initialized. Capitalization check will be disabled.", langCode), e);
      }
      return true;
    }
  }

  private static boolean isDescProperlyCapitalized(String text, Lang nativeLanguage) {
    if ((text == null || text.length() == 0)) {
      return true;
    }

    JLanguageTool tool = LangTool.INSTANCE.getTool(nativeLanguage, TextStyleDomain.CodeDocumentation);
    try {
      List<AnalyzedSentence> analyzedText = tool.analyzeText(text);
      for (AnalyzedSentence sentence : analyzedText) {
        // Ignore non-word tokens (whitespace, punctuation, etc.)
        // Rule-based check
        boolean insideQuotes = false;
        for (AnalyzedTokenReadings token : sentence.getTokens()) {
          String word = token.getToken();
          if (isIgnorable(token)) {
            continue;
          }
          if (isQuoteSymbol(token, nativeLanguage)) {
            insideQuotes = !(insideQuotes);
          }
          if (insideQuotes) {
            continue;
          }

          boolean shouldBeLowerCase = isToBeLowerCase(token, nativeLanguage);
          char firstChar = word.charAt(0);
          if (shouldBeLowerCase) {
            if (Character.isUpperCase(firstChar)) {
              return false;
            }
          } else {
            if (Character.isLowerCase(firstChar)) {
              return false;
            }
          }
        }
      }
    } catch (IOException e) {
      LOG.fatal("Failed to analyze text. " + text, e);
    }
    return true;
  }


  private static boolean isIgnorable(AnalyzedTokenReadings token) {
    String word = token.getToken();
    return word.trim().isEmpty() || token.isWhitespace() || token.isFieldCode();
  }

  private static boolean isQuoteSymbol(AnalyzedTokenReadings token, Lang nativeLanguLang) {
    if (token == null || token.getStartPos() == 0) {
      return false;
    }
    List<AnalyzedToken> readings = token.getReadings();
    for (AnalyzedToken analyzedToken : readings) {
      String tagDesc = analyzedToken.getPOSTag();
      if ("_QM_OPEN".equals(tagDesc) || "_QM_CLOSE".equals(tagDesc)) {
        return true;
      }
    }
    return false;
  }

  private static boolean isToBeLowerCase(AnalyzedTokenReadings token, Lang nativeLanguLang) {
    if (token == null || token.getStartPos() == 0) {
      return false;
    }
    List<AnalyzedToken> readings = token.getReadings();
    LogContext.with(NativeLanguageAnalyzer.class, null, null, null).error("All tokens " + readings);
    for (AnalyzedToken analyzedToken : readings) {
      String tagDesc = analyzedToken.getPOSTag();
      NativeLanguageUtil.Category category = NativeLanguageUtil.getCategory(tagDesc, nativeLanguLang);
      LogContext.with(NativeLanguageAnalyzer.class, null, null, null).error("Token " + tagDesc + ":***" + category);
      if (category != NativeLanguageUtil.Category.OTHER) {
        return true;
      }
    }
    return false;
  }
}
